答案:
将$i(0)=2.19\times10^{-3}\mathrm{A}$代入$i_d = 10^{-14}(\mathrm{e}^{\frac{u_d}{0.026}} - 1)$解得$u_{d0}=0.679\mathrm{V}$。将$i_d = 10^{-14}(\mathrm{e}^{\frac{u_d}{0.026}} - 1)$在$(u_{d0},i_0)$处展开为泰勒级数，并取一次近似，有
\begin{align*}
i_d&=i_0+\Delta i_d = i_0 + 10^{-14}\cdot\frac{1}{0.026}\cdot\mathrm{e}^{\frac{u_{d0}}{0.026}}\cdot\Delta u_d\\
\Delta i_d&=10^{-14}\cdot\frac{1}{0.026}\cdot\mathrm{e}^{\frac{u_{d0}}{0.026}}\cdot\Delta u_d = 0.085\cdot\Delta u_d
\end{align*}
即在$(u_{d0},i_0)$附近$i_d = f(u_d)$的线性化方程为$\Delta i_d = 0.085\cdot\Delta u_d$。

(a)
\begin{align*}
x(t)&=2+(t - t_0)\\
X(s)&=\frac{2}{s}+\frac{1}{s^2}e^{-t_0s}
\end{align*}
(b)
\begin{align*}
x(t)&=1\cdot 1(t - 1)+\frac{1}{2}(t - 1)-2\cdot 1(t - 3)-\frac{1}{2}(t - 3)\\
X(s)&=\frac{e^{-s}}{s^2}(s+\frac{1}{2})-\frac{e^{-3s}}{s^2}(2s+\frac{1}{2})
\end{align*}
(c)
\begin{align*}
x(t)&=a+(b - a)(t - t_1)-(b - c)(t - t_2)-c(t - t_3)\\
X(s)&=\frac{1}{s}[a+(b - a)e^{-t_1s}-(b - c)e^{-t_2s}-ce^{-t_3s}]
\end{align*}
(d)
\begin{align*}
x(t)&=\frac{4}{T^2}t-\frac{4}{T^2}(t-\frac{T}{2})-\frac{4}{T^2}(t-\frac{T}{2})+\frac{4}{T^2}(t - T)\\
X(s)&=\frac{4}{T^2s^2}(1 - 2e^{-\frac{T}{2}s}+e^{-Ts})
\end{align*}

图中有4条前向通路，5个回路、
\begin{align*}
P_1&=-G_1,\quad P_2 = G_1G_2,\quad P_3 = G_2,\quad P_4 = G_2G_1,\\
L_1&=G_1,\quad L_2=-G_1G_2,\quad L_3=-G_2,\quad L_4=-G_2G_1,\quad L_5=-G_1G_2,\\
\Delta_1&=\Delta_2=\Delta_3=\Delta_4 = 1,\quad \Delta = 1-(L_1 + L_2 + L_3 + L_4)
\end{align*}
则有
\begin{align*}
\frac{C(s)}{R(s)}&=\frac{P_1\Delta_1 + P_2\Delta_2 + P_3\Delta_3 + P_4\Delta_4}{\Delta}\\
&=\frac{-G_1+G_1G_2+G_2+G_2G_1}{1 - G_1+G_1G_2+G_2+G_2G_1+G_1G_2}=\frac{2G_1G_2 - G_1+G_2}{1 - G_1+G_2+3G_1G_2}
\end{align*}

设单位阶跃输入$R(s)=\frac{1}{s}$。
当初始条件为$0$时有$\frac{C(s)}{R(s)}=\frac{\tau s + 1}{Ts + 1}$。
所以
\begin{align*}
C(s)&=\frac{\tau s + 1}{Ts + 1}\cdot\frac{1}{s}=\frac{1}{s}-\frac{T - \tau}{Ts + 1}\\
C(t)&=h(t)=1-\frac{T - \tau}{T}e^{-t/T}
\end{align*}
(1) 当$t = t_d$时
\begin{align*}
h(t)&=0.5=1-\frac{T - \tau}{T}e^{-t_d/T}\\
\frac{1}{2}&=\frac{T - \tau}{T}e^{-t_d/T}；-\ln2=\ln\left(\frac{T - \tau}{T}\right)-\frac{t_d}{T}
\end{align*}
所以$t_d=T\left[\ln2+\ln\left(\frac{T - \tau}{T}\right)\right]$。
(2) 求$t_r$（即$c(t)$从$0.1$到$0.9$所需时间）
当$h(t)=0.9=1-\frac{T - \tau}{T}e^{-t_2/T}$；$t_2=T\left[\ln\left(\frac{T - \tau}{T}\right)-\ln0.1\right]$
当$h(t)=0.1=1-\frac{T - \tau}{T}e^{-t_1/T}$；$t_1=T\left[\ln\left(\frac{T - \tau}{T}\right)-\ln0.9\right]$
则$t_r=t_2 - t_1=T\ln\frac{0.9}{0.1}=2.2T$。
(3) 求$t_s$
\begin{align*}
h(t_s)&=0.95=1-\frac{T - \tau}{T}e^{-t_s/T}\\
t_s&=T\left[\ln\frac{T - \tau}{T}-\ln0.05\right]=T\left[\ln\frac{T - \tau}{T}+\ln20\right]=T\left[3+\ln\frac{T - \tau}{T}\right]
\end{align*}

依题意有
\begin{align*}
v(t)&=10\ (\text{V})\\
\omega(\infty)&=\frac{1200\times 2\pi}{60}=40\pi\ (\text{rad}/\text{s})\\
\omega(1.2)&=0.5\omega(\infty)=20\pi\ (\text{rad}/\text{s})
\end{align*}
设系统传递函数$G_0(s)=\frac{\Omega(s)}{V(s)}=\frac{K}{s + a}$
应有
\begin{align*}
\omega(\infty)&=\lim_{s \to 0}sG_0(s)\cdot V(s)=\lim_{s \to 0}s\cdot\frac{10}{s}\cdot\frac{K}{s + a}=\frac{10K}{a}=40\pi\\
\omega(t)&=\mathcal{L}^{-1}[G_0(s)\cdot V(s)]=\mathcal{L}^{-1}\left[\frac{10K}{s(s + a)}\right]=\frac{10K}{a}\mathcal{L}^{-1}\left[\frac{1}{s}-\frac{1}{s + a}\right]=\frac{10K}{a}[1 - \text{e}^{-at}]
\end{align*}
由式(2)，式(3)
\begin{align*}
\omega(1.2)&=\frac{10K}{a}[1 - \text{e}^{-1.2a}]=40\pi[1 - \text{e}^{-1.2a}]=20\pi
\end{align*}
得
\begin{align*}
1 - \text{e}^{-1.2a}&=0.5
\end{align*}
解出
\begin{align*}
a&=\frac{-\ln0.5}{1.2}=0.5776
\end{align*}
将式(4)代入式(3)得
\begin{align*}
K&=4\pi a = 7.2586
\end{align*}
